INSERT INTO site_content (id, siteId, pageSlug, lang, content, updatedAt) VALUES ('38edf101-e018-4ab9-9bec-e07b6d9a7ab3', 'site_dannis_naomi_01', 'home', 'en', '{"welcome_title": "You''re Invited", "welcome_body": "We want you to know how excited we are to have you with us! To make your arrival as smooth as possible, please take a moment to RSVP by August 1, 2026. Your response will greatly help us in preparing for your visit.", "home-welcome": "We want you to know how excited we are to have you with us! To make your arrival as smooth as possible, please take a moment to RSVP by August 1, 2026. Your response will greatly help us in preparing for your visit."}', 1775858043892) ON CONFLICT (siteId, pageSlug, lang) DO UPDATE SET content = excluded.content, updatedAt = excluded.updatedAt;
INSERT INTO site_content (id, siteId, pageSlug, lang, content, updatedAt) VALUES ('67ab9b42-de6f-4b2a-8aea-71473ed2a488', 'site_dannis_naomi_01', 'story', 'en', '{"body": "Dannis Seay and Naomi Nguyen''s story began at Toast & Berry, unfolding like a scene from a romantic comedy. Naomi arrived at the wrong location, leaving Dannis waiting for an entire hour. Yet, when she finally arrived, he couldn''t take his eyes off her. Naomi was immediately charmed by his warm smile, kind eyes, and effortless conversation, along with his gentlemanly manners.\n\nFollowing that first date, Dannis sent a message that kept their connection alive, inviting Naomi on a second date: Hawaiian food at Onolicious, followed by a ride on the Cincinnati Bell streetcar. Amidst laughter, conversation, and delicious food, it became clear that something truly special was blossoming.\n\nThe couple embraced several mini-adventures, exploring Lexington, KY, with friends, visiting a castle, wandering through outdoor shopping centers, and traveling to Knoxville, TN, for brewery hopping and quality time with friends. Each shared experience deepened their bond, cultivating laughter, inside jokes, and cherished memories.\n\nDannis traveled to Tiền Giang, Vietnam, to meet Naomi''s family, and from the moment he arrived, he was welcomed with open arms, home-cooked meals, and the warmth of a close-knit family. Together, they explored the Mekong Delta, Da Nang, Huế, and Hội An, sharing meals, coffee, and heartfelt conversations. A memorable moment was sitting down with Naomi''s parents to discuss their future; though nervous, Dannis felt a sense of acceptance and support.\n\nBack home, the adventures continued as Naomi experienced her first pontoon ride at Kentucky Lake. The couple celebrated friends'' birthdays, explored seafood and coffee spots in Cincinnati, cooked new dishes together, and gamed side by side, weaving love into the fabric of their lives.\n\nThrough it all, it''s the everyday moments that inspire the most: Dannis caring for Naomi and their pets, Naomi''s kindness, and their shared laughter. Together, they''ve built a life founded on love, curiosity, and adventure—and they look forward to a future of exploration, learning, and growth side by side.", "story": "Dannis Seay and Naomi Nguyen''s story began at Toast & Berry, unfolding like a scene from a romantic comedy. Naomi arrived at the wrong location, leaving Dannis waiting for an entire hour. Yet, when she finally arrived, he couldn''t take his eyes off her. Naomi was immediately charmed by his warm smile, kind eyes, and effortless conversation, along with his gentlemanly manners.\n\nFollowing that first date, Dannis sent a message that kept their connection alive, inviting Naomi on a second date: Hawaiian food at Onolicious, followed by a ride on the Cincinnati Bell streetcar. Amidst laughter, conversation, and delicious food, it became clear that something truly special was blossoming.\n\nThe couple embraced several mini-adventures, exploring Lexington, KY, with friends, visiting a castle, wandering through outdoor shopping centers, and traveling to Knoxville, TN, for brewery hopping and quality time with friends. Each shared experience deepened their bond, cultivating laughter, inside jokes, and cherished memories.\n\nDannis traveled to Tiền Giang, Vietnam, to meet Naomi''s family, and from the moment he arrived, he was welcomed with open arms, home-cooked meals, and the warmth of a close-knit family. Together, they explored the Mekong Delta, Da Nang, Huế, and Hội An, sharing meals, coffee, and heartfelt conversations. A memorable moment was sitting down with Naomi''s parents to discuss their future; though nervous, Dannis felt a sense of acceptance and support.\n\nBack home, the adventures continued as Naomi experienced her first pontoon ride at Kentucky Lake. The couple celebrated friends'' birthdays, explored seafood and coffee spots in Cincinnati, cooked new dishes together, and gamed side by side, weaving love into the fabric of their lives.\n\nThrough it all, it''s the everyday moments that inspire the most: Dannis caring for Naomi and their pets, Naomi''s kindness, and their shared laughter. Together, they''ve built a life founded on love, curiosity, and adventure—and they look forward to a future of exploration, learning, and growth side by side."}', 1775858043892) ON CONFLICT (siteId, pageSlug, lang) DO UPDATE SET content = excluded.content, updatedAt = excluded.updatedAt;
INSERT INTO site_content (id, siteId, pageSlug, lang, content, updatedAt) VALUES ('de91d0d1-4f94-488c-b433-487d33392614', 'site_dannis_naomi_01', 'travel', 'en', '{"heading": "Travel", "body": "Getting Started\nA Vietnam eVisa is required for most international visitors. Apply for a single-entry eVisa before your trip at the official Vietnam government portal.\nApply for eVisa: https://evisa.xuatnhapcanh.gov.vn/\n\nGetting In\nFly into Tân Sơn Nhất International Airport (SGN) in Ho Chi Minh City. This airport offers a convenient entry point to begin your journey with us. We recommend choosing airlines that have layovers in South Korea, Japan, Hong Kong, or Taiwan for the best connections.\n\nGetting Around\nThere are many ways to get around Ho Chi Minh City! Grab (regular vehicles) and XanhSM (electric vehicles) are both affordable — similar to Uber, and both accept international credit cards.\n\nPlaces to Stay in HCMC\nIf you''re planning to arrive early or extend your stay after the wedding, we highly encourage you to book a hotel in District 1, 2, 3, or 5. This area offers a lively atmosphere, easy access to the city''s top attractions, and great restaurants. Staying here also means the shuttle can easily pick you up on the morning of January 17.", "travel": "Getting Started\nA Vietnam eVisa is required for most international visitors. Apply for a single-entry eVisa before your trip at the official Vietnam government portal.\nApply for eVisa: https://evisa.xuatnhapcanh.gov.vn/\n\nGetting In\nFly into Tân Sơn Nhất International Airport (SGN) in Ho Chi Minh City. This airport offers a convenient entry point to begin your journey with us. We recommend choosing airlines that have layovers in South Korea, Japan, Hong Kong, or Taiwan for the best connections.\n\nGetting Around\nThere are many ways to get around Ho Chi Minh City! Grab (regular vehicles) and XanhSM (electric vehicles) are both affordable — similar to Uber, and both accept international credit cards.\n\nPlaces to Stay in HCMC\nIf you''re planning to arrive early or extend your stay after the wedding, we highly encourage you to book a hotel in District 1, 2, 3, or 5. This area offers a lively atmosphere, easy access to the city''s top attractions, and great restaurants. Staying here also means the shuttle can easily pick you up on the morning of January 17.", "sections": [{"heading": "Getting Started", "body": "A Vietnam eVisa is required for most international visitors. Apply for a single-entry eVisa before your trip at the official Vietnam government portal.", "link_label": "Apply for eVisa", "link_url": "https://evisa.xuatnhapcanh.gov.vn/"}, {"heading": "Getting In", "body": "Fly into Tân Sơn Nhất International Airport (SGN) in Ho Chi Minh City. This airport offers a convenient entry point to begin your journey with us. We recommend choosing airlines that have layovers in South Korea, Japan, Hong Kong, or Taiwan for the best connections.", "link_label": null, "link_url": null}, {"heading": "Getting Around", "body": "There are many ways to get around Ho Chi Minh City! Grab (regular vehicles) and XanhSM (electric vehicles) are both affordable — similar to Uber, and both accept international credit cards.", "link_label": null, "link_url": null}, {"heading": "Places to Stay in HCMC", "body": "If you''re planning to arrive early or extend your stay after the wedding, we highly encourage you to book a hotel in District 1, 2, 3, or 5. This area offers a lively atmosphere, easy access to the city''s top attractions, and great restaurants. Staying here also means the shuttle can easily pick you up on the morning of January 17.", "link_label": null, "link_url": null}]}', 1775858043892) ON CONFLICT (siteId, pageSlug, lang) DO UPDATE SET content = excluded.content, updatedAt = excluded.updatedAt;
INSERT INTO site_content (id, siteId, pageSlug, lang, content, updatedAt) VALUES ('461e8491-30d3-4140-9c24-c3fe56011fd1', 'site_dannis_naomi_01', 'accommodations', 'en', '{"intro": "We are thrilled to share our wedding day with all of you! We understand that traveling can be a significant commitment, so we are pleased to offer everyone a complimentary stay at the resort on the night of the wedding. This way, you can fully immerse yourselves in the celebration without feeling rushed. If you''re coming from a distance, we recommend arriving a day early to allow time to relax and settle in before the festivities begin.", "accommodations": "We are thrilled to share our wedding day with all of you! We understand that traveling can be a significant commitment, so we are pleased to offer everyone a complimentary stay at the resort on the night of the wedding. This way, you can fully immerse yourselves in the celebration without feeling rushed. If you''re coming from a distance, we recommend arriving a day early to allow time to relax and settle in before the festivities begin.", "hotel_name": "Lan Rung Beach Resort", "hotel_description": "We love Lan Rung Beach Resort for its picturesque location right on the beach — perfect for a romantic beach wedding getaway. The rooms are clean and comfortable, the staff are friendly and accommodating, and the affordable price range makes it a great option for all guests.", "room_block_note": "Rooms have not been released for the event dates yet. Check back soon for booking details."}', 1775858043892) ON CONFLICT (siteId, pageSlug, lang) DO UPDATE SET content = excluded.content, updatedAt = excluded.updatedAt;
INSERT INTO site_content (id, siteId, pageSlug, lang, content, updatedAt) VALUES ('2b31a7f2-c7b6-42b9-998a-8311d1c7c370', 'site_dannis_naomi_01', 'registry', 'en', '{"intro": "Your presence is enough of a present to us! But for those of you who are stubborn, we''ve put together a wish-list to help you out.", "registry": "Your presence is enough of a present to us! But for those of you who are stubborn, we''ve put together a wish-list to help you out.", "item_name": "Home Down Payment", "item_description": "Contribute what you wish toward our future home.", "cta": "Contribute via PayPal"}', 1775858043892) ON CONFLICT (siteId, pageSlug, lang) DO UPDATE SET content = excluded.content, updatedAt = excluded.updatedAt;
INSERT INTO site_content (id, siteId, pageSlug, lang, content, updatedAt) VALUES ('f6eeb0b8-7847-43b5-89ca-50cf819cd589', 'site_dannis_naomi_01', 'faq', 'en', '{"intro": "For all our friends and family who have lots of questions, please check out our Q & A first!", "questions": [{"q": "When is the RSVP deadline?", "a": "We''d love to hear from you! Please let us know if you can make it by August, so we can get an accurate headcount. Thanks a bunch!"}, {"q": "What will the weather be like?", "a": "During the day, expect beautiful, sunny skies with temperatures around 82–85°F (about 28–29°C)."}, {"q": "Is the wedding indoors or outdoors?", "a": "Our wedding ceremony will take place outdoors, with vows on the beach and the reception by the pool."}, {"q": "What should I wear?", "a": "Check out our schedule for the dress code details. Just a little tip: the coastal breeze can make things a bit chilly at night, so it''s a great idea to pack a light sweater or wrap to keep cozy during those beautiful evenings."}, {"q": "What kind of shoes should/shouldn''t I wear?", "a": "We recommend wearing comfortable shoes or sandals for the vow ceremony, as it will take place on the sand. For the reception, feel free to wear your favorite stylish shoes — whether elegant heels or trendy flats, choose something that makes you feel great while allowing you to dance and celebrate!"}, {"q": "Is it okay to take pictures during the wedding?", "a": "We would love for you to take and share photos throughout the celebration! For the vow ceremony, though, we invite you to be fully present with us and kindly ask that all devices be put away."}, {"q": "Can I bring a date?", "a": "Please check your invite for your +1!"}, {"q": "Are kids welcome?", "a": "We absolutely love your little ones, but we kindly ask for a kid-free ceremony and reception. Kids are totally welcome at the pre-wedding lunch and post-wedding breakfast — just let us know in advance so we can accommodate everyone comfortably!"}, {"q": "Will the reception be live streamed?", "a": "We''re excited to share that we have a talented local streamer from the bride''s side who will be capturing all the unforgettable moments throughout the event — Cậu tư 😜"}, {"q": "How will food and drinks be served?", "a": "We have a cocktail bar where you can enjoy tasty desserts and tropical cocktails before the ceremony starts. After that, get ready for a buffet meal at the reception that''ll have something for everyone!"}, {"q": "What if I have a dietary restriction?", "a": "Please take a moment to answer the dietary question in your RSVP, or feel free to reach out to us directly. We want to make sure you have the best possible experience!"}, {"q": "Whom should I contact with questions?", "a": "For assistance, please reach out to Dannis or Naomi via their phone numbers or social media accounts."}]}', 1775858043892) ON CONFLICT (siteId, pageSlug, lang) DO UPDATE SET content = excluded.content, updatedAt = excluded.updatedAt;
INSERT INTO site_content (id, siteId, pageSlug, lang, content, updatedAt) VALUES ('23fef241-7efa-4f5c-979c-e70f159c4ca8', 'site_dannis_naomi_01', 'schedule', 'en', '{"events": [{"name": "Shuttle Bus 🧳🚌", "date": "Sunday, January 17", "time": "7:00 – 11:00 AM", "location": "Nhà Phân Phối VLXD Tín Nghĩa Mỹ, Gò Công Tây, Tiền Giang", "description": "Shuttle buses will be leaving from the Tin Nghia My company in Go Cong Tay, and heading straight to Lan Rung resort in Phuoc Hai, Vung Tau. We can''t wait to see you there—so please try not to be late! For those who are not from there and need a ride to Lan Rung, we''re more than happy to help arrange transportation. Just let us know!", "maps_url": "https://www.google.com/maps/search/?api=1&query=Nh%C3%A0+Ph%C3%A2n+Ph%E1%BB%91i+VLXD+T%C3%ADn+Ngh%C4%A9a+M%E1%BB%B9", "dress_code": ""}, {"name": "Pre-Wedding Lunch 🥗🍹", "date": "Sunday, January 17", "time": "11:00 AM – 1:00 PM", "location": "Lan Rung Beach Resort, Phước Hải, Bà Rịa - Vũng Tàu", "description": "After we arrive at the resort, we will check into our rooms and enjoy a delightful lunch together.", "maps_url": "https://www.google.com/maps/search/?api=1&query=Lan+Rung+Beach+Resort", "dress_code": ""}, {"name": "Relaxing Time 👟💄", "date": "Sunday, January 17", "time": "1:00 – 4:00 PM", "location": "Lan Rung Beach Resort, Phước Hải, Bà Rịa - Vũng Tàu", "description": "Time to get ready and dress up for the wedding ceremony. If you have a little extra time before things kick off, feel free to take a stroll around the resort and check out all the fun amenities!", "maps_url": "https://www.google.com/maps/search/?api=1&query=Lan+Rung+Beach+Resort", "dress_code": ""}, {"name": "Ceremony & Reception 🥳🎈", "date": "Sunday, January 17", "time": "4:00 PM", "location": "Lan Rung Beach Resort, Phước Hải, Bà Rịa - Vũng Tàu", "description": "We''re thrilled to announce that we''re tying the knot! Join us for an evening filled with joy, laughter, and celebration as we share our love with all of you. Enjoy delicious cocktails, a delightful dinner, and refreshing drinks as we kick off this exciting new chapter together!", "maps_url": "https://www.google.com/maps/search/?api=1&query=Lan+Rung+Beach+Resort", "dress_code": "Cocktail Attire"}, {"name": "Post-Wedding Breakfast 🥐🥂", "date": "Monday, January 18", "time": "7:00 – 9:00 AM", "location": "Lan Rung Beach Resort, Phước Hải, Bà Rịa - Vũng Tàu", "description": "We would love to gather with all our guests for a buffet breakfast at the resort the morning after the wedding. It will be a wonderful opportunity for everyone to relax, share stories from the celebration, and enjoy a variety of breakfast options together. We hope you''ll join us for this special moment!", "maps_url": "https://www.google.com/maps/search/?api=1&query=Lan+Rung+Beach+Resort", "dress_code": ""}, {"name": "Bye Bye Bye 🏖️👋", "date": "Monday, January 18", "time": "9:00 – 11:00 AM", "location": "Lan Rung Beach Resort, Phước Hải, Bà Rịa - Vũng Tàu", "description": "Feel free to enjoy the resort''s amenities until check-out, whether by the pool, on the beach, or at the spa. Once everyone has checked out, we will gather at the bus for our return to Tien Giang at Tin Nghia My Company. We truly appreciate you being here to celebrate this special destination wedding with us. It''s a day we''ll remember fondly for years to come!", "maps_url": "https://www.google.com/maps/search/?api=1&query=Lan+Rung+Beach+Resort", "dress_code": ""}]}', 1775858043892) ON CONFLICT (siteId, pageSlug, lang) DO UPDATE SET content = excluded.content, updatedAt = excluded.updatedAt;
INSERT INTO site_content (id, siteId, pageSlug, lang, content, updatedAt) VALUES ('4563dbf6-eb4b-457c-b3e8-93aac0650503', 'site_dannis_naomi_01', 'home', 'vi', '{"welcome_title": "Mời Bạn Tham Dự", "welcome_body": "Tụi mình thiệt sự rất vui khi biết các bạn sẽ có mặt! Để việc đi lại được thuận tiện nha, mọi người nhớ xác nhận tham dự trước ngày 1 tháng 8 năm 2026 nhé. Phản hồi của các bạn sẽ giúp tụi mình chuẩn bị chu đáo hơn rất nhiều.", "home-welcome": "Tụi mình thiệt sự rất vui khi biết các bạn sẽ có mặt! Để việc đi lại được thuận tiện nha, mọi người nhớ xác nhận tham dự trước ngày 1 tháng 8 năm 2026 nhé. Phản hồi của các bạn sẽ giúp tụi mình chuẩn bị chu đáo hơn rất nhiều."}', 1775858043892) ON CONFLICT (siteId, pageSlug, lang) DO UPDATE SET content = excluded.content, updatedAt = excluded.updatedAt;
INSERT INTO site_content (id, siteId, pageSlug, lang, content, updatedAt) VALUES ('2a9c1f81-53a0-4288-8c3c-0d0af3cf7b79', 'site_dannis_naomi_01', 'story', 'vi', '{"body": "Câu chuyện của Dannis Seay và Naomi Nguyễn bắt đầu tại Toast & Berry, như một cảnh trong bộ phim tình cảm hài hước. Naomi đến nhầm địa điểm, khiến Dannis phải chờ đợi cả tiếng đồng hồ. Thế mà khi nàng xuất hiện, anh không thể rời mắt khỏi nàng được. Naomi ngay lập tức bị cuốn hút bởi nụ cười ấm áp, ánh mắt hiền lành và cách trò chuyện tự nhiên của anh, cùng với phong cách lịch thiệp đáng yêu của anh.\n\nSau buổi hẹn đầu tiên đó, Dannis nhắn tin giữ lửa mối duyên, mời Naomi đi ăn Hawaii tại Onolicious rồi cùng nhau đi tàu điện Cincinnati Bell. Giữa những tràng cười, câu chuyện và những món ăn ngon, cả hai đều cảm nhận được điều gì đó thật đặc biệt đang nảy nở.\n\nHai người cùng nhau trải qua nhiều chuyến phiêu lưu nhỏ: khám phá Lexington, KY cùng bạn bè, thăm lâu đài, dạo quanh các khu mua sắm ngoài trời, và đến Knoxville, TN để thưởng thức bia thủ công và gặp gỡ bạn bè. Mỗi kỷ niệm chung đều thắt chặt thêm sợi dây gắn kết, tạo nên những tiếng cười, câu chuyện riêng và ký ức đẹp.\n\nDannis đến Tiền Giang, Việt Nam, để gặp gia đình Naomi. Từ khoảnh khắc đặt chân đến, anh đã được đón tiếp nồng hậu bằng vòng tay mở rộng, những bữa cơm nhà ấm lòng và sự gần gũi của một gia đình đoàn kết. Cả hai cùng nhau khám phá miền Tây sông nước, Đà Nẵng, Huế và Hội An — chia sẻ bữa ăn, ly cà phê và những cuộc trò chuyện chân thành. Khoảnh khắc đáng nhớ nhất là lúc ngồi nói chuyện với ba má Naomi về tương lai; dù hồi hộp, Dannis vẫn cảm nhận được sự đồng ý và ủng hộ từ gia đình.\n\nVề lại quê nhà, những chuyến phiêu lưu vẫn tiếp tục khi Naomi lần đầu tiên trải nghiệm chuyến đi thuyền tại Kentucky Lake. Hai người cùng nhau mừng sinh nhật bạn bè, khám phá các quán hải sản và cà phê ở Cincinnati, nấu những món mới, và chơi game cạnh nhau — dệt thêm tình yêu vào từng ngày sống.\n\nQua tất cả những điều đó, chính những khoảnh khắc bình dị nhất lại truyền cảm hứng nhiều nhất: Dannis chăm sóc Naomi và những người bạn nhỏ bốn chân, sự dịu dàng của Naomi, và những tràng cười không dứt của cả hai. Cùng nhau, họ đã xây dựng một cuộc sống trên nền tảng tình yêu, sự tò mò và tinh thần phiêu lưu — và họ háo hức hướng về một tương lai khám phá, học hỏi và trưởng thành bên nhau.", "story": "Câu chuyện của Dannis Seay và Naomi Nguyễn bắt đầu tại Toast & Berry, như một cảnh trong bộ phim tình cảm hài hước. Naomi đến nhầm địa điểm, khiến Dannis phải chờ đợi cả tiếng đồng hồ. Thế mà khi nàng xuất hiện, anh không thể rời mắt khỏi nàng được. Naomi ngay lập tức bị cuốn hút bởi nụ cười ấm áp, ánh mắt hiền lành và cách trò chuyện tự nhiên của anh, cùng với phong cách lịch thiệp đáng yêu của anh.\n\nSau buổi hẹn đầu tiên đó, Dannis nhắn tin giữ lửa mối duyên, mời Naomi đi ăn Hawaii tại Onolicious rồi cùng nhau đi tàu điện Cincinnati Bell. Giữa những tràng cười, câu chuyện và những món ăn ngon, cả hai đều cảm nhận được điều gì đó thật đặc biệt đang nảy nở.\n\nHai người cùng nhau trải qua nhiều chuyến phiêu lưu nhỏ: khám phá Lexington, KY cùng bạn bè, thăm lâu đài, dạo quanh các khu mua sắm ngoài trời, và đến Knoxville, TN để thưởng thức bia thủ công và gặp gỡ bạn bè. Mỗi kỷ niệm chung đều thắt chặt thêm sợi dây gắn kết, tạo nên những tiếng cười, câu chuyện riêng và ký ức đẹp.\n\nDannis đến Tiền Giang, Việt Nam, để gặp gia đình Naomi. Từ khoảnh khắc đặt chân đến, anh đã được đón tiếp nồng hậu bằng vòng tay mở rộng, những bữa cơm nhà ấm lòng và sự gần gũi của một gia đình đoàn kết. Cả hai cùng nhau khám phá miền Tây sông nước, Đà Nẵng, Huế và Hội An — chia sẻ bữa ăn, ly cà phê và những cuộc trò chuyện chân thành. Khoảnh khắc đáng nhớ nhất là lúc ngồi nói chuyện với ba má Naomi về tương lai; dù hồi hộp, Dannis vẫn cảm nhận được sự đồng ý và ủng hộ từ gia đình.\n\nVề lại quê nhà, những chuyến phiêu lưu vẫn tiếp tục khi Naomi lần đầu tiên trải nghiệm chuyến đi thuyền tại Kentucky Lake. Hai người cùng nhau mừng sinh nhật bạn bè, khám phá các quán hải sản và cà phê ở Cincinnati, nấu những món mới, và chơi game cạnh nhau — dệt thêm tình yêu vào từng ngày sống.\n\nQua tất cả những điều đó, chính những khoảnh khắc bình dị nhất lại truyền cảm hứng nhiều nhất: Dannis chăm sóc Naomi và những người bạn nhỏ bốn chân, sự dịu dàng của Naomi, và những tràng cười không dứt của cả hai. Cùng nhau, họ đã xây dựng một cuộc sống trên nền tảng tình yêu, sự tò mò và tinh thần phiêu lưu — và họ háo hức hướng về một tương lai khám phá, học hỏi và trưởng thành bên nhau."}', 1775858043892) ON CONFLICT (siteId, pageSlug, lang) DO UPDATE SET content = excluded.content, updatedAt = excluded.updatedAt;
INSERT INTO site_content (id, siteId, pageSlug, lang, content, updatedAt) VALUES ('03a90ee7-5efd-423d-ac28-27da1daee245', 'site_dannis_naomi_01', 'travel', 'vi', '{"heading": "Di Chuyển", "body": "Trước Khi Khởi Hành\nHầu hết du khách quốc tế cần xin visa điện tử (eVisa) trước khi nhập cảnh Việt Nam. Mọi người vào trang web chính thức của chính phủ để đăng ký visa một lần nhập cảnh nha.\nĐăng Ký eVisa: https://evisa.xuatnhapcanh.gov.vn/\n\nBay Đến Việt Nam\nMọi người bay vào Sân Bay Quốc Tế Tân Sơn Nhất (SGN) ở Thành phố Hồ Chí Minh nha. Đây là điểm đến thuận tiện nhất để bắt đầu hành trình cùng tụi mình. Tụi mình gợi ý chọn hãng hàng không có transit ở Hàn Quốc, Nhật Bản, Hồng Kông hoặc Đài Loan để có chuyến bay kết nối tốt nhất.\n\nDi Chuyển Trong Thành Phố\nThành phố Hồ Chí Minh có nhiều lựa chọn đi lại! Grab (xe thông thường) và XanhSM (xe điện) đều rẻ và tiện lợi — giống Grab bên mình vậy, và cả hai đều chấp nhận thẻ quốc tế.\n\nNơi Lưu Trú ở TP. Hồ Chí Minh\nNếu mọi người đến sớm hoặc muốn ở lại thêm sau đám cưới, tụi mình khuyến khích đặt khách sạn ở Quận 1, 2, 3 hoặc 5. Khu vực này nhộn nhịp, gần nhiều địa danh nổi tiếng, nhà hàng ngon và tiện đi lại. Ở đây cũng giúp xe buýt đưa đón dễ dàng đón mọi người vào sáng ngày 17 tháng 1.", "travel": "Trước Khi Khởi Hành\nHầu hết du khách quốc tế cần xin visa điện tử (eVisa) trước khi nhập cảnh Việt Nam. Mọi người vào trang web chính thức của chính phủ để đăng ký visa một lần nhập cảnh nha.\nĐăng Ký eVisa: https://evisa.xuatnhapcanh.gov.vn/\n\nBay Đến Việt Nam\nMọi người bay vào Sân Bay Quốc Tế Tân Sơn Nhất (SGN) ở Thành phố Hồ Chí Minh nha. Đây là điểm đến thuận tiện nhất để bắt đầu hành trình cùng tụi mình. Tụi mình gợi ý chọn hãng hàng không có transit ở Hàn Quốc, Nhật Bản, Hồng Kông hoặc Đài Loan để có chuyến bay kết nối tốt nhất.\n\nDi Chuyển Trong Thành Phố\nThành phố Hồ Chí Minh có nhiều lựa chọn đi lại! Grab (xe thông thường) và XanhSM (xe điện) đều rẻ và tiện lợi — giống Grab bên mình vậy, và cả hai đều chấp nhận thẻ quốc tế.\n\nNơi Lưu Trú ở TP. Hồ Chí Minh\nNếu mọi người đến sớm hoặc muốn ở lại thêm sau đám cưới, tụi mình khuyến khích đặt khách sạn ở Quận 1, 2, 3 hoặc 5. Khu vực này nhộn nhịp, gần nhiều địa danh nổi tiếng, nhà hàng ngon và tiện đi lại. Ở đây cũng giúp xe buýt đưa đón dễ dàng đón mọi người vào sáng ngày 17 tháng 1.", "sections": [{"heading": "Trước Khi Khởi Hành", "body": "Hầu hết du khách quốc tế cần xin visa điện tử (eVisa) trước khi nhập cảnh Việt Nam. Mọi người vào trang web chính thức của chính phủ để đăng ký visa một lần nhập cảnh nha.", "link_label": "Đăng Ký eVisa", "link_url": "https://evisa.xuatnhapcanh.gov.vn/"}, {"heading": "Bay Đến Việt Nam", "body": "Mọi người bay vào Sân Bay Quốc Tế Tân Sơn Nhất (SGN) ở Thành phố Hồ Chí Minh nha. Đây là điểm đến thuận tiện nhất để bắt đầu hành trình cùng tụi mình. Tụi mình gợi ý chọn hãng hàng không có transit ở Hàn Quốc, Nhật Bản, Hồng Kông hoặc Đài Loan để có chuyến bay kết nối tốt nhất.", "link_label": null, "link_url": null}, {"heading": "Di Chuyển Trong Thành Phố", "body": "Thành phố Hồ Chí Minh có nhiều lựa chọn đi lại! Grab (xe thông thường) và XanhSM (xe điện) đều rẻ và tiện lợi — giống Grab bên mình vậy, và cả hai đều chấp nhận thẻ quốc tế.", "link_label": null, "link_url": null}, {"heading": "Nơi Lưu Trú ở TP. Hồ Chí Minh", "body": "Nếu mọi người đến sớm hoặc muốn ở lại thêm sau đám cưới, tụi mình khuyến khích đặt khách sạn ở Quận 1, 2, 3 hoặc 5. Khu vực này nhộn nhịp, gần nhiều địa danh nổi tiếng, nhà hàng ngon và tiện đi lại. Ở đây cũng giúp xe buýt đưa đón dễ dàng đón mọi người vào sáng ngày 17 tháng 1.", "link_label": null, "link_url": null}]}', 1775858043892) ON CONFLICT (siteId, pageSlug, lang) DO UPDATE SET content = excluded.content, updatedAt = excluded.updatedAt;
INSERT INTO site_content (id, siteId, pageSlug, lang, content, updatedAt) VALUES ('a881f50b-9f8e-4af2-97a7-c13e97446b56', 'site_dannis_naomi_01', 'accommodations', 'vi', '{"intro": "Tụi mình rất vui khi được đón tiếp mọi người trong ngày trọng đại này! Biết rằng đi lại xa xôi là cả một sự cố gắng lớn, nên tụi mình sẽ lo chỗ ở tại resort cho tất cả mọi người vào đêm đám cưới hoàn toàn miễn phí. Mọi người cứ thư thả tận hưởng buổi tiệc mà không lo vội về nha. Nếu đến từ xa, tụi mình gợi ý mọi người đến sớm một ngày để nghỉ ngơi và ổn định trước khi vào tiệc.", "accommodations": "Tụi mình rất vui khi được đón tiếp mọi người trong ngày trọng đại này! Biết rằng đi lại xa xôi là cả một sự cố gắng lớn, nên tụi mình sẽ lo chỗ ở tại resort cho tất cả mọi người vào đêm đám cưới hoàn toàn miễn phí. Mọi người cứ thư thả tận hưởng buổi tiệc mà không lo vội về nha. Nếu đến từ xa, tụi mình gợi ý mọi người đến sớm một ngày để nghỉ ngơi và ổn định trước khi vào tiệc.", "hotel_name": "Lan Rung Beach Resort", "hotel_description": "Tụi mình chọn Lan Rung Beach Resort vì vị trí đẹp ngay trên bãi biển — lý tưởng cho một đám cưới bãi biển lãng mạn. Phòng sạch sẽ thoải mái, nhân viên thân thiện nhiệt tình, và giá cả phải chăng rất phù hợp cho tất cả khách mời.", "room_block_note": "Phòng cho ngày tổ chức sự kiện chưa được mở đặt. Mọi người theo dõi thêm để cập nhật thông tin đặt phòng nha."}', 1775858043892) ON CONFLICT (siteId, pageSlug, lang) DO UPDATE SET content = excluded.content, updatedAt = excluded.updatedAt;
INSERT INTO site_content (id, siteId, pageSlug, lang, content, updatedAt) VALUES ('83c68fcf-c8f4-467e-adc7-422183fac4e8', 'site_dannis_naomi_01', 'registry', 'vi', '{"intro": "Sự hiện diện của mọi người đã là món quà ý nghĩa nhất rồi! Nhưng với những ai nhất quyết muốn tặng quà, tụi mình có chuẩn bị một danh sách nhỏ để các bạn tham khảo nha.", "registry": "Sự hiện diện của mọi người đã là món quà ý nghĩa nhất rồi! Nhưng với những ai nhất quyết muốn tặng quà, tụi mình có chuẩn bị một danh sách nhỏ để các bạn tham khảo nha.", "item_name": "Góp Quỹ Mua Nhà", "item_description": "Đóng góp bao nhiêu tùy tấm lòng để giúp tụi mình có mái ấm riêng.", "cta": "Đóng Góp qua PayPal"}', 1775858043892) ON CONFLICT (siteId, pageSlug, lang) DO UPDATE SET content = excluded.content, updatedAt = excluded.updatedAt;
INSERT INTO site_content (id, siteId, pageSlug, lang, content, updatedAt) VALUES ('41751bce-ac79-4193-b95f-992748cf224d', 'site_dannis_naomi_01', 'faq', 'vi', '{"intro": "Cho tất cả bạn bè và gia đình có nhiều thắc mắc, mọi người xem qua phần Hỏi & Đáp này trước nha!", "questions": [{"q": "Hạn chót xác nhận tham dự là khi nào?", "a": "Tụi mình rất muốn biết mọi người có đến được hông! Nhờ mọi người xác nhận trước tháng 8 để tụi mình biết số lượng mà chuẩn bị cho chu đáo nha. Cảm ơn mọi người nhiều lắm!"}, {"q": "Thời tiết hôm đó sẽ như thế nào?", "a": "Ban ngày trời nắng đẹp, nhiệt độ khoảng 28–29°C. Thích hợp cho đám cưới bãi biển lắm nha!"}, {"q": "Lễ cưới tổ chức trong nhà hay ngoài trời?", "a": "Lễ đính hôn sẽ tổ chức ngoài trời ngay trên bãi biển, còn tiệc cưới thì ở khu vực hồ bơi."}, {"q": "Nên mặc đồ gì?", "a": "Mọi người xem phần Lịch Trình để biết quy định trang phục nha. Tụi mình cũng gợi ý mang theo áo khoác nhẹ vì ban đêm ở biển hay có gió lạnh."}, {"q": "Nên đi giày như thế nào?", "a": "Ở phần lễ trên bãi biển, mọi người mang dép hoặc giày đế bằng thoải mái cho dễ đi trên cát nha. Còn ở tiệc cưới thì tự do chọn đôi giày yêu thích — miễn là mình cảm thấy đẹp và thoải mái để nhảy múa là được!"}, {"q": "Có được chụp ảnh trong đám cưới hông?", "a": "Tụi mình rất muốn mọi người chụp và chia sẻ ảnh suốt buổi tiệc! Tuy nhiên, trong phần lễ thành hôn, tụi mình mong mọi người để điện thoại xuống và cùng hiện diện trọn vẹn với tụi mình nha."}, {"q": "Có được dẫn người đi cùng hông?", "a": "Mọi người kiểm tra trong thiệp mời xem có +1 hông nha!"}, {"q": "Trẻ em có được tham dự hông?", "a": "Tụi mình yêu các bé lắm, nhưng lễ cưới và tiệc chính là dành cho người lớn nha. Các bé được chào đón tại bữa trưa trước lễ (ngày 17) và bữa sáng sau lễ (ngày 18) — chỉ cần báo trước để tụi mình sắp xếp cho chu đáo là được!"}, {"q": "Tiệc cưới có được livestream hông?", "a": "Có nha! Phía cô dâu có một người livestream tài năng sẽ ghi lại tất cả những khoảnh khắc đáng nhớ trong suốt buổi tiệc — Cậu tư 😜"}, {"q": "Thức ăn và đồ uống phục vụ như thế nào?", "a": "Trước lễ cưới sẽ có quầy cocktail với bánh ngọt và cocktail nhiệt đới. Sau đó là tiệc buffet với nhiều món đa dạng cho tất cả mọi người!"}, {"q": "Nếu tôi có chế độ ăn kiêng đặc biệt thì sao?", "a": "Mọi người điền vào phần câu hỏi về ăn uống khi xác nhận tham dự, hoặc liên hệ trực tiếp với tụi mình nha. Tụi mình muốn đảm bảo mọi người có trải nghiệm tốt nhất!"}, {"q": "Cần hỗ trợ thì liên hệ ai?", "a": "Mọi người liên hệ Dannis hoặc Naomi qua số điện thoại hoặc mạng xã hội nha."}]}', 1775858043892) ON CONFLICT (siteId, pageSlug, lang) DO UPDATE SET content = excluded.content, updatedAt = excluded.updatedAt;
INSERT INTO site_content (id, siteId, pageSlug, lang, content, updatedAt) VALUES ('c0a5686a-9636-4035-8a80-fb56207b9589', 'site_dannis_naomi_01', 'schedule', 'vi', '{"events": [{"name": "Xe Đưa Đón 🧳🚌", "date": "Chủ Nhật, ngày 17 tháng 1", "time": "7:00 – 11:00 SA", "location": "Nhà Phân Phối VLXD Tín Nghĩa Mỹ, Gò Công Tây, Tiền Giang", "description": "Xe buýt sẽ xuất phát từ Nhà Phân Phối VLXD Tín Nghĩa Mỹ ở Gò Công Tây và chạy thẳng tới khu resort Lan Rung ở Phước Hải, Vũng Tàu. Tụi mình nóng lòng gặp mọi người lắm rồi — nên đừng trễ nha! Ai không ở khu đó mà cần xe tới Lan Rung, cứ liên hệ tụi mình để sắp xếp nha.", "maps_url": "https://www.google.com/maps/search/?api=1&query=Nh%C3%A0+Ph%C3%A2n+Ph%E1%BB%91i+VLXD+T%C3%ADn+Ngh%C4%A9a+M%E1%BB%B9", "dress_code": ""}, {"name": "Bữa Trưa Trước Lễ Cưới 🥗🍹", "date": "Chủ Nhật, ngày 17 tháng 1", "time": "11:00 SA – 1:00 CH", "location": "Lan Rung Beach Resort, Phước Hải, Bà Rịa - Vũng Tàu", "description": "Sau khi đến resort, mọi người nhận phòng rồi cùng nhau ăn trưa vui vẻ nha.", "maps_url": "https://www.google.com/maps/search/?api=1&query=Lan+Rung+Beach+Resort", "dress_code": ""}, {"name": "Thời Gian Nghỉ Ngơi 👟💄", "date": "Chủ Nhật, ngày 17 tháng 1", "time": "1:00 – 4:00 CH", "location": "Lan Rung Beach Resort, Phước Hải, Bà Rịa - Vũng Tàu", "description": "Tranh thủ thời gian này để trang điểm và mặc đồ đẹp trước khi vào lễ cưới nha. Ai còn thời gian thì cứ tự do dạo quanh resort tham quan nhé!", "maps_url": "https://www.google.com/maps/search/?api=1&query=Lan+Rung+Beach+Resort", "dress_code": ""}, {"name": "Lễ Cưới & Tiệc Mừng 🥳🎈", "date": "Chủ Nhật, ngày 17 tháng 1", "time": "4:00 CH", "location": "Lan Rung Beach Resort, Phước Hải, Bà Rịa - Vũng Tàu", "description": "Tụi mình chính thức về chung một nhà rồi! Mời mọi người cùng đến chia vui, cười thật nhiều và cùng nhau tận hưởng một buổi tối đáng nhớ. Sẽ có cocktail, tiệc buffet và thật nhiều niềm vui đang chờ đón mọi người!", "maps_url": "https://www.google.com/maps/search/?api=1&query=Lan+Rung+Beach+Resort", "dress_code": "Cocktail Attire"}, {"name": "Bữa Sáng Sau Đám Cưới 🥐🥂", "date": "Thứ Hai, ngày 18 tháng 1", "time": "7:00 – 9:00 SA", "location": "Lan Rung Beach Resort, Phước Hải, Bà Rịa - Vũng Tàu", "description": "Tụi mình muốn mời tất cả mọi người dùng bữa sáng buffet tại resort vào sáng hôm sau. Đây là dịp để mọi người cùng nghỉ ngơi, kể chuyện vui từ hôm qua và thưởng thức bữa sáng thư thả bên nhau. Hy vọng gặp đủ mặt nha!", "maps_url": "https://www.google.com/maps/search/?api=1&query=Lan+Rung+Beach+Resort", "dress_code": ""}, {"name": "Tạm Biệt Nha 🏖️👋", "date": "Thứ Hai, ngày 18 tháng 1", "time": "9:00 – 11:00 SA", "location": "Lan Rung Beach Resort, Phước Hải, Bà Rịa - Vũng Tàu", "description": "Mọi người tự do tận hưởng các tiện ích của resort đến giờ trả phòng — bơi hồ, tắm biển hay nghỉ spa đều được hết. Khi mọi người đã trả phòng xong, cả đoàn sẽ tập hợp lên xe về lại Tiền Giang tại Nhà Tín Nghĩa Mỹ. Cảm ơn mọi người đã đến chung vui với tụi mình trong ngày trọng đại này. Đây là ký ức tụi mình sẽ trân trọng mãi!", "maps_url": "https://www.google.com/maps/search/?api=1&query=Lan+Rung+Beach+Resort", "dress_code": ""}]}', 1775858043892) ON CONFLICT (siteId, pageSlug, lang) DO UPDATE SET content = excluded.content, updatedAt = excluded.updatedAt;
